Year(3); // Adds 3 years to current date","line":3919,"params":[{"type":"Number","optional":false,"name":"years","title":"Years to add."}],"return":{"type":"Date","title":"New Date after addition."}},"equals":{"title":"Determines whether current date equals the specified date.","line":3938,"params":[{"type":"Date","optional":false,"name":"date","title":"Date to compare."}],"return":{"type":"Boolean","title":"`true` if equal, `false` otherwise."}},"equalsDate":{"title":"Determines whether the date part of current date equals that of the specified date.","line":3946,"params":[{"type":"Date","optional":false,"name":"date","title":"Date to compare."}],"return":{"type":"Boolean","title":"`true` if equal, `false` otherwise."}},"equalsMonth":{"title":"Determines whether the year and month parts of current date equals those of the specified date.","line":3958,"params":[{"type":"Date","optional":false,"name":"date","title":"Date to compare."}],"return":{"type":"Boolean","title":"`true` if equal, `false` otherwise."}}},"property":{"dateText":{"line":3971,"getter":{"type":"String","title":"Local date string (4-digit year, 2-digit month and day).\n Example:\n\n     new Date().dateText; // eg: \"10/05/2025\""}},"timeText":{"line":3985,"getter":{"type":"String","title":"Local time string in 24-hour format (2-digit hours, minutes, seconds)\n Example:\n\n     new Date().timeText; // eg: \"15:03:23\""}},"timeTextHM":{"line":3999,"getter":{"type":"String","title":"Local time string in 24-hour format (2-digit hours and minutes).\n Example:\n\n     new Date().timeTextHM; // eg: \"15:03\""}},"timeText12":{"line":4013,"getter":{"type":"String","title":"Local time string in 12-hour format (2-digit hours, minutes, seconds).\n Example:\n\n     new Date().timeText12; // eg: \"02:15:29 PM\""}},"timeText12HM":{"line":4027,"getter":{"type":"String","title":"Local time string in 12-hour format (2-digit hours and minutes).\n Example:\n\n     new Date().timeText12HM; // eg: \"02:15 PM\""}},"dateTi